@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private int activeChannelId;
    private Channel? activeChannel;
    private string newMessageContent = "";
    private string threadReplyContent = "";
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();
    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private int pageSize = 30;
    private ElementReference messageListRef;
    private DotNetObjectReference<Chat>? dotNetRef;

    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "🤔", "👀" };

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Any())
        {
            await SelectChannelAsync(channels.First());
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannelId = channel.Id;
        activeChannel = channel;
        messages.Clear();
        threadSummaries.Clear();
        hasMoreMessages = true;
        emojiPickerMessageId = null;

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, pageSize);
        hasMoreMessages = messages.Count >= pageSize;
        await BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        // Messages that are replies indicate thread starters
        var replyGroups = messages
            .Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value))
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            var replies = group.OrderBy(m => m.SentAt).ToList();
            threadSummaries[group.Key] = new ThreadSummary(group.Key, replies.Count, replies.Last().SentAt);
        }

        // Also check via GetThreadAsync for root messages without inline replies
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !threadSummaries.ContainsKey(m.Id)))
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                if (thread.Count > 0)
                {
                    threadSummaries[msg.Id] = new ThreadSummary(msg.Id, thread.Count, thread.Last().SentAt);
                }
            }
            catch
            {
                // Thread may not exist for this message
            }
        }
    }

    private async Task OnMessageListScroll()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        // Check scroll position via JS interop
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessages();
        }
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, pageSize);
        if (older.Count < pageSize)
        {
            hasMoreMessages = false;
        }

        messages.InsertRange(0, older);
        await BuildThreadSummaries();
        isLoadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageContent) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageContent.Trim(), null);
        messages.Add(sent);
        newMessageContent = "";
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadOpen = true;
        threadReplyContent = "";
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyContent) || threadRootMessage is null || activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyContent.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        threadReplyContent = "";

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, threadReplies.Count, reply.SentAt);
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messages.Count);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }

    public ValueTask DisposeAsync()
    {
        dotNetRef?.Dispose();
        return ValueTask.CompletedTask;
    }
}

