}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #f9f9f9;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
}

